        const d = obj.data;
        console.log(`データ内容: quotes=${(d.quotes||[]).length}件, companies=${(d.companies||[]).length}, vendors=${(d.vendors||[]).length}, munis=${(d.municipalities||[]).length}, tasks=${(d.tasks||[]).length}`);
