async function sbGet(id) {
  try {
    const r = await fetch(`${DB_API_BASE}/data?id=${encodeURIComponent(id)}`, {
      headers: { ...DB_API_HEADERS, "Accept-Encoding": "gzip" },
    });
    if (!r.ok) return null;
    // ブラウザは Content-Encoding: gzip を自動展開するので、そのまま json() 可
    const obj = await r.json();
    if (obj && obj.data !== undefined) {
      return { _rawData: obj.data, _updatedAt: obj.updated_at ?? null };
    }
    return null;
  } catch (e) {
    console.warn("[sbGet] failed:", e);
    return null;
  }
}

// gzip圧縮ヘルパー
async function _gzipBody(jsonStr) {
  if (typeof CompressionStream === "undefined") return null;
  const stream = new Blob([jsonStr]).stream().pipeThrough(new CompressionStream("gzip"));
  return await new Response(stream).blob();
}

async function sbSet(id, data) {
  const now = new Date().toISOString();
  window.__myDeskLastSave = Date.now();
  window.__myDeskLastSaveAt = now;
  const MAX_RETRY = 5;  // 3→5に増加
  const jsonStr = JSON.stringify({ id, data });
  // 100KB以上ならgzip圧縮で送信
  let body, extraHeaders = {};
  if (jsonStr.length > 100 * 1024) {
    const gzipped = await _gzipBody(jsonStr);
    if (gzipped) {
      body = gzipped;
      extraHeaders = { "Content-Encoding": "gzip" };
    } else {
      body = jsonStr;
    }
  } else {
    body = jsonStr;
  }
  console.log(`[MyDesk] sbSet POST → ${DB_API_BASE}/data (id=${id}, size=${jsonStr.length}B${jsonStr.length>100*1024?', gzipped':''})`);
  for(let attempt = 1; attempt <= MAX_RETRY; attempt++) {
    try {
      const res = await fetch(`${DB_API_BASE}/data`, {
        method: "POST",
        headers: { ...DB_API_HEADERS, ...extraHeaders },
        body,
        keepalive: jsonStr.length < 60 * 1024,
      });
      if(!res.ok) {
        const errText = await res.text().catch(()=>"");
        throw new Error(`${res.status} ${errText}`);
      }
      console.log(`[MyDesk] sbSet OK (attempt ${attempt})`);
      // 成功したら緊急バックアップを削除
      if (id === "main") {
        try { localStorage.removeItem("md_emergency_backup"); } catch {}
      }
      return true;
    } catch(e) {
      console.warn(`[MyDesk] sbSet attempt ${attempt}/${MAX_RETRY} failed: ${e.message}`);
      if(attempt < MAX_RETRY) {
        await new Promise(r => setTimeout(r, attempt * 800));  // 1000→800ms
      } else {
        console.error("[MyDesk] sbSet all retries failed:", e.message);
        window.__myDeskLastSave = 0;
        window.__myDeskLastSaveAt = null;
        // 緊急バックアップ - localStorage に保存
        if (id === "main") {
          try {
            // 大きいので圧縮版 or 重要部分だけ
            const backup = {
              savedAt: new Date().toISOString(),
              error: e.message,
              dataSize: jsonStr.length,
              // データ全体は5MBまでlocalStorageに入る
              dataPreview: jsonStr.length < 5 * 1024 * 1024 ? data : null,
            };
            localStorage.setItem("md_emergency_backup", JSON.stringify(backup));
          } catch {}
          // ユーザーに通知（控えめに）
          try {
            window.dispatchEvent(new CustomEvent("md_save_failed", { detail: { error: e.message } }));
          } catch {}
        }
        return false;
      }
    }
  }
}

