// ─── 案内状の変数差し込み: {{QR_CODE}}, {{VENDOR_NAME}}, {{DATE}} 等を置換 ─────
function renderAnnouncementTemplate(html, vendor, qrImgUrl) {
  if (!html) return "";
  const today = new Date();
  const yyyy = today.getFullYear();
  const mm = String(today.getMonth()+1).padStart(2,"0");
  const dd = String(today.getDate()).padStart(2,"0");
  const dateJp = `${yyyy}年${today.getMonth()+1}月${today.getDate()}日`;
  const dateIso = `${yyyy}-${mm}-${dd}`;
  
  const vendorName = vendor?.vendor_name || vendor?.name || "";
  const vendorPhone = vendor?.phone || vendor?.tel || "";
  const vendorEmail = vendor?.email || "";
  const vendorAddress = vendor?.address || "";
  
  return html
    // QRコード
    .replace(/\{\{QR_CODE\}\}/g, qrImgUrl 
      ? `<img src="${qrImgUrl}" style="width:150px;height:150px;display:inline-block;" alt="QR"/>` 
      : '<div style="display:inline-block;padding:0.5rem;background:#f0f0f0;border:1px dashed #999;border-radius:4px;font-size:0.7rem;color:#666;">[QRコード]</div>')
    // 業者情報
    .replace(/\{\{VENDOR_NAME\}\}/g, vendorName)
    .replace(/\{\{業者名\}\}/g, vendorName)
    .replace(/\{\{VENDOR_PHONE\}\}/g, vendorPhone)
    .replace(/\{\{業者電話\}\}/g, vendorPhone)
    .replace(/\{\{VENDOR_EMAIL\}\}/g, vendorEmail)
    .replace(/\{\{業者メアド\}\}/g, vendorEmail)
    .replace(/\{\{VENDOR_ADDRESS\}\}/g, vendorAddress)
    .replace(/\{\{業者住所\}\}/g, vendorAddress)
    // 日付
    .replace(/\{\{DATE\}\}/g, dateJp)
    .replace(/\{\{日付\}\}/g, dateJp)
    .replace(/\{\{DATE_ISO\}\}/g, dateIso)
    .replace(/\{\{YEAR\}\}/g, String(yyyy))
    .replace(/\{\{年\}\}/g, String(yyyy))
    .replace(/\{\{MONTH\}\}/g, String(today.getMonth()+1))
    .replace(/\{\{月\}\}/g, String(today.getMonth()+1))
    .replace(/\{\{DAY\}\}/g, String(today.getDate()))
    .replace(/\{\{日\}\}/g, String(today.getDate()));
}

// ─── QR反応から営業データ（プロジェクト + 企業 + 名刺）を作成する共通ヘルパー ─────
async function createProjectFromQrSubmission(sub, ctx, currentUserId) {
  try {
    if (typeof window.__myDeskSetData !== "function") {
      alert("プロジェクト作成エラー: setData が利用できません");
      return;
    }
    const company = sub.company_name || "(企業名未入力)";
    const pjName = `${company} (${ctx.announcementTitle || "QR反応"})`;
    const now = new Date().toISOString();
    const rand = () => Math.random().toString(36).slice(2,7);
    
    // 名前を 姓/名 に分割（半角・全角スペース対応）
    let lastName = sub.contact_name || "";
    let firstName = "";
    if (lastName) {
      const m = lastName.match(/^(\S+)[\s　]+(\S+.*)$/);
      if (m) {
        lastName = m[1];
        firstName = m[2];
      }
    }
    
    window.__myDeskSetData(prev => {
      const next = {...prev};
      
      // 1. 企業マスタへ自動登録（同名企業がある場合はそれを使う）
      let companyId = null;
      const existingCompany = (next.companies || []).find(c => c.name === company && company !== "(企業名未入力)");
      if (existingCompany) {
        companyId = existingCompany.id;
      } else if (company !== "(企業名未入力)") {
        companyId = `co_${Date.now()}_${rand()}`;
        const newCompany = {
          id: companyId,
          name: company,
          phone: sub.phone || "",
          email: sub.email || "",
          status: "新規",
          memo: `[QR反応から自動登録]\n発行業者: ${ctx.vendorName || "(不明)"}\n案内状: ${ctx.announcementTitle || "(不明)"}`,
          createdAt: now,
          createdBy: currentUserId || "",
          assigneeIds: [],
          source: "qr_form",
        };
        next.companies = [...(next.companies || []), newCompany];
      }
      
      // 2. 名刺登録（重複チェック: 同社・同名なら追加しない）
      let bizcardId = null;
      if (sub.contact_name && company !== "(企業名未入力)") {
        const dup = (next.businessCards || []).find(bc => 
          bc.company === company && bc.lastName === lastName && bc.firstName === firstName
        );
        if (dup) {
          bizcardId = dup.id;
        } else {
          bizcardId = `bc_${Date.now()}_${rand()}`;
          const newBizcard = {
            id: bizcardId,
            company,
            companyId,
            lastName,
            firstName,
            email: sub.email || "",
            mobile: sub.phone || "",
            tel: sub.phone || "",
            owners: currentUserId ? [currentUserId] : [],
            note: `[QR反応から自動登録]\n発行業者: ${ctx.vendorName || "(不明)"}`,
            createdAt: now,
          };
          next.businessCards = [...(next.businessCards || []), newBizcard];
        }
      }
      
      // 3. プロジェクト作成
      const newProject = {
        id: `pj_${Date.now()}_${rand()}`,
        name: pjName,
        stage: "新規",
        vendorId: ctx.vendorId || "",
        companyId: companyId || "",
        bizcardId: bizcardId || "",
        memo: `[QR反応から自動作成]\n発行業者: ${ctx.vendorName || "(不明)"}\n案内状: ${ctx.announcementTitle || "(不明)"}\n\n【お問い合わせ内容】\n会社名: ${sub.company_name || "(未入力)"}\n担当者: ${sub.contact_name || "(未入力)"}\n電話: ${sub.phone || "(未入力)"}\nメール: ${sub.email || "(未入力)"}\n\n【アンケート回答】\n${Object.entries(sub.form_data||{}).filter(([k,v])=>k&&v).map(([k,v])=>`・${k}: ${Array.isArray(v)?v.join(", "):v}`).join("\n") || "(なし)"}\n\n送信日時: ${new Date(sub.submitted_at).toLocaleString("ja-JP")}`,
        contactName: sub.contact_name || "",
        contactPhone: sub.phone || "",
        contactEmail: sub.email || "",
        createdAt: now,
        createdBy: currentUserId || "",
        source: "qr_form",
        qrSubmissionId: sub.id,
      };
      next.projects = [...(next.projects || []), newProject];
      return next;
    });
    
    const messages = [`✅ プロジェクト「${pjName}」を作成しました`];
    if (company !== "(企業名未入力)") {
      messages.push(`✅ 企業「${company}」を登録 / 更新`);
    }
    if (sub.contact_name) {
      messages.push(`✅ 名刺「${sub.contact_name}（${company}）」を登録`);
    }
    alert(messages.join("\n"));
  } catch(e) {
    alert("プロジェクト作成エラー: " + e.message);
  }
}

function _quickHash(s) {
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h + s.charCodeAt(i)) | 0;
  }
  return h.toString(36);
}

async function _processSaveQueue() {
  // ★ ロード失敗中はキュー処理自体をスキップ（INIT 空データの誤保存を防ぐ）
  if (typeof window !== "undefined" && window.__myDeskLoadError) {
    console.warn("[MyDesk] _processSaveQueue skipped — load error state");
    __pendingSaveData = null; // キューもクリア
    return;
  }
  if (__isCurrentlySaving) return;
  while (__pendingSaveData) {
    // ★ closure 問題対策：保存直前に最新ステート取得
    // 複数の setData が連続実行された場合、各 setData の closure は古い data を見ている
    // window.__myDeskGetData() で常に最新のステートを取得することで、変更の取りこぼしを防ぐ
    let toSave = __pendingSaveData;
    try {
      if (typeof window !== "undefined" && typeof window.__myDeskGetData === "function") {
        const latest = window.__myDeskGetData();
        if (latest && typeof latest === "object" && Object.keys(latest).length > 0) {
          toSave = latest;
        }
      }
    } catch (e) {
      console.warn("[MyDesk] getLatestData failed, using cached pending:", e);
    }
    __pendingSaveData = null;
    __isCurrentlySaving = true;
    try {
      const jsonStr = JSON.stringify(toSave);
      const hash = _quickHash(jsonStr);
      if (hash === __lastSavedHash) {
        console.log("[MyDesk] scheduleSaveData skipped — no changes since last save");
      } else {
        await saveData(toSave);
        __lastSavedHash = hash;
      }
    } catch (e) {
      console.error("[MyDesk] queued save failed:", e);
    } finally {
      __isCurrentlySaving = false;
    }
  }
}

function scheduleSaveData(d) {
  // ★ ロード失敗中はスケジュールしない（INIT 空データ保存防止の最終ライン）
  if (typeof window !== "undefined" && window.__myDeskLoadError) {
    console.warn("[MyDesk] scheduleSaveData skipped — load error state");
    return;
  }
  if (!d || typeof d !== "object") return;
  // 重要なフィールド数をログ
  const c = (d.companies||[]).length;
  const v = (d.vendors||[]).length;
  const t = (d.tasks||[]).length;
  console.log(`[MyDesk] scheduleSaveData queued: companies=${c}, vendors=${v}, tasks=${t}`);
  __pendingSaveData = d;
  if (__saveTimer) clearTimeout(__saveTimer);
  __saveTimer = setTimeout(() => {
    __saveTimer = null;
    _processSaveQueue();
  }, SAVE_DEBOUNCE_MS);
}

// ページ離脱時に未保存があれば即時保存
if (typeof window !== "undefined" && !window.__myDeskFlushListenerAdded) {
  window.__myDeskFlushListenerAdded = true;
  const flush = () => {
    if (__saveTimer) { clearTimeout(__saveTimer); __saveTimer = null; }
    if (__pendingSaveData) {
      try {
        saveData(__pendingSaveData); // fire-and-forget; keepaliveで完了
        __pendingSaveData = null;
      } catch (_) {}
    }
  };
  window.addEventListener("beforeunload", (e) => {
    if (__pendingSaveData || __isCurrentlySaving) {
      flush();
      e.preventDefault();
      e.returnValue = "未保存の変更があります。本当にページを離れますか？";
      return e.returnValue;
    }
  });
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState === "hidden") flush();
  });
}

